import CooperativeList from '../../components/CooperativeList';
import Map from '../../components/Map';
import { cooperatives } from '../../data/mockData';

export default function ExplorePage() {
  const totalProducts = cooperatives.reduce((count, cooperative) => {
    return count + cooperative.products.length;
  }, 0);

  return (
    <section id="cooperatives" className="space-y-4">
      <div className="rounded-2xl border border-white/40 bg-white/70 p-5 shadow-lg backdrop-blur-md">
        <h1 className="text-2xl font-semibold text-palmier">Explorer les cooperatives</h1>
        <p className="mt-2 text-sm text-palmier/80">
          Cliquez sur une carte ou un marqueur pour synchroniser instantanement la selection.
        </p>
        <div className="mt-4 flex flex-wrap gap-2 text-xs">
          <span className="rounded-full bg-terracotta/10 px-3 py-1 font-medium text-terracotta">
            {cooperatives.length} cooperatives
          </span>
          <span className="rounded-full bg-palmier/10 px-3 py-1 font-medium text-palmier">
            {totalProducts} produits
          </span>
          <span className="rounded-full bg-sable/20 px-3 py-1 font-medium text-palmier">
            Region Draa-Tafilalet
          </span>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4 lg:grid-cols-[1.6fr_1fr]">
        <Map cooperatives={cooperatives} />
        <CooperativeList cooperatives={cooperatives} />
      </div>
    </section>
  );
}
